	["REG_PLAYER_TUTO_ABOUT_MISC_1"] = [=[Esta selección te ofrece |cnGREEN_FONT_COLOR:5 ranuras|r con las que se puede describir |cnGREEN_FONT_COLOR:las piezas más importantes de tu personaje|r.

